213e6e85-13f1-441a-a7e2-08c7600ecca4	jobs.fetch_scheduled_jobs	fetch jobs from scheduled_jobs table filtered by status	fetch jobs scheduled jobs list show jobs completed jobs failed jobs scheduled jobs filter jobs by status view job queue job status jobs table get all jobs	[]	Call dynamic_select_query to fetch jobs from the scheduled_jobs table.\n\n  - table: "scheduled_jobs"\n  - projection: ["id", "job_name", "schedule_time", "status",]\n  - limit: 100\n\n  STATUS FILTER RULES:\n    - If the user asks for "completed" jobs → where: "status = 'Completed'"\n    - If the user asks for "failed" jobs     → where: "status = 'Failed'"\n    - If the user asks for "scheduled" jobs  → where: "status = 'Scheduled'"\n    - If no status is mentioned              → omit the where clause and return all jobs\n\n  Return the results directly to the user as a table or list.\n  Do NOT generate raw SQL manually.\n  Do NOT call any other tool.	[{"args": {"limit": 100, "table": "scheduled_jobs", "where": "$STATUS_FILTER_OR_OMIT", "order_by": ["schedule_time DESC"], "projection": ["id", "job_name", "schedule_time", "status"]}, "step": 1, "tool": "dynamic_select_query"}]	["NO_RAW_SQL", "SINGLE_STEP_ONLY", "STATUS_MUST_BE_ONE_OF_Scheduled_Completed_Failed", "OMIT_WHERE_IF_NO_STATUS_SPECIFIED", "RETURN_RESULTS_DIRECTLY_NO_PDF_NO_CHART"]	[-0.10682551,0.04319195,-0.009977084,-0.023420168,0.01903709,-0.011499646,-0.06905145,0.045216754,0.028524296,-0.06398469,0.027761606,-0.027168782,-0.004716729,-0.108321816,0.072711214,0.053064983,0.045390766,0.067225076,-0.0019901006,0.08180266,-0.01720031,-0.011572923,-0.01947049,-0.014269961,0.01882885,-0.022325879,0.028827118,-0.036603186,-0.017626317,0.022806048,0.014992073,-0.0052255476,0.051528472,0.008151972,0.05405479,0.027549222,0.0382733,-0.034490414,0.07315728,-0.026759183,-0.025488673,0.029787574,-0.011987179,-0.016981278,-0.004549779,-0.027188705,0.009681042,0.0022927942,-0.044492282,-0.016345048,0.009537123,-0.034571256,-0.019545851,0.05569326